#!/usr/bin/env python3
"""Materialize the complete Starfire SGP CNN/RNN dataset bundle.

This bootstrap is intentionally self-contained so GitHub Actions can regenerate
and commit the full expanded corpora without transporting multi-megabyte JSONL
through the GitHub connector.
"""
from __future__ import annotations

import argparse
import base64
import hashlib
import io
import json
import shutil
import subprocess
import sys
import tarfile
import zipfile
from pathlib import Path

PAYLOAD_B64 = """"""


def run(*args: str, cwd: Path | None = None, stdout: Path | None = None) -> None:
    target = stdout.open("w", encoding="utf-8") if stdout else None
    try:
        subprocess.run(args, cwd=cwd, check=True, text=True, stdout=target)
    finally:
        if target:
            target.close()


def sha256(path: Path) -> str:
    h = hashlib.sha256()
    with path.open("rb") as handle:
        for chunk in iter(lambda: handle.read(1024 * 1024), b""):
            h.update(chunk)
    return h.hexdigest()


def unpack_payload(source_root: Path) -> None:
    if source_root.exists():
        shutil.rmtree(source_root)
    source_root.mkdir(parents=True)
    raw = base64.b64decode(PAYLOAD_B64)
    with tarfile.open(fileobj=io.BytesIO(raw), mode="r:gz") as archive:
        archive.extractall(source_root, filter="data")


def write_checksums(root: Path) -> None:
    lines = []
    for path in sorted(p for p in root.rglob("*") if p.is_file() and p.name != "SHA256SUMS"):
        lines.append(f"{sha256(path)}  {path.relative_to(root).as_posix()}")
    (root / "SHA256SUMS").write_text("\n".join(lines) + "\n", encoding="utf-8")


def make_zip(root: Path, destination: Path) -> None:
    destination.parent.mkdir(parents=True, exist_ok=True)
    if destination.exists():
        destination.unlink()
    with zipfile.ZipFile(destination, "w", compression=zipfile.ZIP_DEFLATED, compresslevel=9) as archive:
        for path in sorted(p for p in root.rglob("*") if p.is_file() and p != destination):
            archive.write(path, arcname=f"starfire_sgp_training_bundle_v1/{path.relative_to(root).as_posix()}")


def main() -> None:
    parser = argparse.ArgumentParser()
    parser.add_argument("--source-root", type=Path, required=True)
    parser.add_argument("--output-root", type=Path, required=True)
    args = parser.parse_args()
    source_root = args.source_root.resolve()
    output_root = args.output_root.resolve()
    unpack_payload(source_root)
    tooling = source_root / "tooling"
    assets = source_root / "assets"

    run(sys.executable, str(tooling / "generate_datasets.py"), "--output", str(output_root))
    shutil.copy2(assets / "README.md", output_root / "README.md")
    shutil.copy2(assets / "DATA_CARD.md", output_root / "DATA_CARD.md")
    shutil.copy2(assets / "TRAINING_GUIDE.md", output_root / "TRAINING_GUIDE.md")
    shutil.copy2(assets / "LICENSE-DATA.md", output_root / "LICENSE-DATA.md")
    shutil.copy2(assets / "dataset-metadata.json", output_root / "dataset-metadata.json")

    reports = output_root / "reports"
    reports.mkdir(parents=True, exist_ok=True)
    for path in sorted((assets / "reports").iterdir()):
        shutil.copy2(path, reports / path.name)

    run(sys.executable, str(tooling / "validate_datasets.py"), str(output_root), stdout=reports / "validation_report.json")
    run(
        sys.executable,
        str(tooling / "check_starfire_rnn_compat.py"),
        str(output_root / "rnn_phrase_ranker" / "train.jsonl"),
        stdout=reports / "current_rnn_compatibility.json",
    )

    review = output_root / "review"
    run(
        sys.executable,
        str(tooling / "make_human_review_sheet.py"),
        str(output_root / "cnn_phrase_ranker" / "full.jsonl"),
        str(review / "cnn_blinded_review.csv"),
        "--per-axis-tier", "5", "--seed", "1729",
        stdout=reports / "cnn_review_sheet.json",
    )
    run(
        sys.executable,
        str(tooling / "make_human_review_sheet.py"),
        str(output_root / "rnn_phrase_ranker" / "full.jsonl"),
        str(review / "rnn_blinded_review.csv"),
        "--per-axis-tier", "5", "--seed", "1729",
        stdout=reports / "rnn_review_sheet.json",
    )

    controls = output_root / "controls"
    run(
        sys.executable,
        str(tooling / "make_controls.py"),
        str(output_root / "rnn_phrase_ranker" / "train.jsonl"),
        str(controls / "rnn"),
        "--seed", "1729",
        stdout=reports / "rnn_controls.log",
    )
    run(
        sys.executable,
        str(tooling / "make_controls.py"),
        str(output_root / "cnn_phrase_ranker" / "train.jsonl"),
        str(controls / "cnn"),
        "--seed", "1729",
        stdout=reports / "cnn_controls.log",
    )

    write_checksums(output_root)
    bundle = output_root / "starfire_sgp_cnn_rnn_training_bundle_v1.zip"
    make_zip(output_root, bundle)
    bundle_digest = sha256(bundle)
    (output_root / "BUNDLE_SHA256").write_text(
        f"{bundle_digest}  {bundle.name}\n", encoding="utf-8"
    )
    print(json.dumps({
        "status": "PASS",
        "source_root": str(source_root),
        "output_root": str(output_root),
        "bundle": str(bundle),
        "bundle_sha256": bundle_digest,
    }, sort_keys=True))


if __name__ == "__main__":
    main()
